import{_ as t,o as a,c as n,a2 as o}from"./chunks/framework.DeNJmwJc.js";const m=JSON.parse('{"title":"Chapter 42 — Change List","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/42-change-list.md","filePath":"chapters/42-change-list.md"}'),i={name:"chapters/42-change-list.md"};function r(s,e,h,c,d,l){return a(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="chapter-42-—-change-list" tabindex="-1">Chapter 42 — Change List <a class="header-anchor" href="#chapter-42-—-change-list" aria-label="Permalink to &quot;Chapter 42 — Change List&quot;">​</a></h1><blockquote><p><em>&quot;Vim tracks every edit you make. Use that to navigate.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐⭐ Intermediate <strong>Estimated Reading Time:</strong> 10 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>While the jump list tracks cursor movement, the <strong>change list</strong> tracks edits.</p><hr><h1 id="change-list-commands" tabindex="-1">Change List Commands <a class="header-anchor" href="#change-list-commands" aria-label="Permalink to &quot;Change List Commands&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>g;</code></td><td>Go to <strong>previous</strong> change position</td></tr><tr><td><code>g,</code></td><td>Go to <strong>next</strong> change position</td></tr><tr><td><code>:changes</code></td><td>List change history</td></tr></tbody></table><hr><h1 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h1><p>Make edits at lines 10, 20, and 30.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>g;   →   jump to edit at line 30</span></span>
<span class="line"><span>g;   →   jump to edit at line 20</span></span>
<span class="line"><span>g;   →   jump to edit at line 10</span></span>
<span class="line"><span>g,   →   jump forward to line 20</span></span>
<span class="line"><span>g,   →   jump forward to line 30</span></span></code></pre></div><hr><h1 id="dot-command-connection" tabindex="-1">Dot Command Connection <a class="header-anchor" href="#dot-command-connection" aria-label="Permalink to &quot;Dot Command Connection&quot;">​</a></h1><p>The change list and dot command are related.</p><p>Each entry in the change list can be repeated with <code>.</code> if you reapply the edit.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li><code>g;</code> goes to previous edit location.</li><li><code>g,</code> goes to next edit location.</li><li><code>:changes</code> shows all edits.</li><li>Changes are tracked per buffer.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Edit text at 5 different lines.</li><li>Navigate backward through edits with <code>g;</code>.</li><li>Navigate forward with <code>g,</code>.</li><li>View the change list with <code>:changes</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./43-vimrc.html"><strong>Chapter 43 — vimrc Configuration</strong></a></p><p>Configure Vim with your personal settings.</p>`,28)])])}const g=t(i,[["render",r]]);export{m as __pageData,g as default};
